_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    float1 d = 0.005;
    float1 dx = ( 2*GetBlur2(vUv + vec2(d,0)) - 2*GetBlur2(vUv-vec2(d,0)) ).x*0.5;
    float1 dy = ( 2*GetBlur2(vUv + vec2(0,d)) - 2*GetBlur2(vUv-vec2(0,d)) ).x*0.5;
    float1 dxb = ( 2*GetBlur2(vUv + vec2(d,0)) - 2*GetBlur2(vUv-vec2(d,0)) ).x*0.5;
    float1 dyb = ( 2*GetBlur2(vUv + vec2(0,d)) - 2*GetBlur2(vUv-vec2(0,d)) ).x*0.5;
    vec2 my_uv = vUv - vec2(dx,dy)*0.005 + vec2(dxb,dyb)*0.002;



    vec2 v = 0.1;
    ret.x = texture( sampler_fc_main, my_uv).x;


    ret.x += (2*ret.x - 2*GetBlur3(vUv).x)*.05;
    ret.x += 0.006;

    ret.x = mix( ret.x, lum(ret).x, 0);

//--------------------------------

    my_uv = vUv + vec2(dy,-dx)*0.025*(2.4-2*GetBlur3(vUv).y);



    v = 0.01;
    ret.z = texture( sampler_fw_main, my_uv).z;


    ret.z += (2*ret.z - 2*GetBlur1(vUv).z)*length(my_uv-vUv)*60;
    ret.z *= 0.85;
    ret.z += 0.008;



//--------------------------------

    d = 0.01;
    my_uv = vec2(-dy,dx)*0.05;

    dx = ( 2*GetBlur2(vUv + vec2(d,0)) - 2*GetBlur2(vUv-vec2(d,0)) ).y*0.5;
    dy = ( 2*GetBlur2(vUv + vec2(0,d)) - 2*GetBlur2(vUv-vec2(0,d)) ).y*0.5;
    my_uv += vUv - vec2(dx,dy)*0.3;



    v = 0.01;
    ret.y =texture( sampler_fw_main, my_uv).y;


    ret.y += (2*ret.y - 2*GetBlur3(my_uv).y)*0.05 + 0.03;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uvo = 0.5 + (vUv-0.5)*vec2(1.1,0.81);
vec2 factorA = vUv-vec2(1-0.5,0.5);

vUv -= 0.5;
vUv *= uAspect.xy;

rs0.x = atan(vUv.y, vUv.x)/3.1416*2;
rs0.y = .02/(length(vUv));
rss = vec2 (rs0.x,rs0.y+uTime);
rss = multiply(rss,mat2(.7,.7,-.7,.7));
float noise = (texture(sampler_pw_noise_lq,rss/32)-.7 >= 0);
rss = abs(fract(rss*8)-.5);
vec3 dots = clamp01(.04/length(rss)) *noise;

rss = vec2 (rs0.x*2,rs0.y+uTime/2);
rss = multiply(rss,mat2(.7,.7,-.7,.7));
noise = (texture(sampler_pw_noise_lq,rss/32)-.7 >= 0);
rss = abs(fract(rss*8)-.5);
dots += clamp01(.04/length(rss)) * noise;

dots *= clamp01(.04/abs(.01/rs0.y-q6*0))+.0;
dots *= dots*2;

vec3 ret1 = 0;
int anz = 2;
int n = 0;
while (n <= anz) {
    ang2 = 6.28*n/anz;
    c = cos(ang2);
    s = sin(ang2);
    uv2.x =  vUv.x*c - vUv.y*s;
    uv2.y =  vUv.x*s + vUv.y*c;

    neu = GetPixel(uv2+.5) + GetBlur1(uv2+.5);
    ret1 = max(ret1,neu);
n++;
}
ret = ret1 + dots*(1+ret1);

vec2 factorB = vec2(0,-1024+(audioHighSmooth-audioLowSmooth)*0);
vec2 product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
vec2 numerator = vec2(1,0);
vec2 denominator = product;
vec2 fraction = vec2( numerator.x*denominator.x + numerator.y*denominator.y,   // the fractions real part
                   numerator.y*denominator.x - numerator.x*denominator.y)/  // the fractions imaginary part
                   (denominator.x*denominator.x + denominator.y*denominator.y);
vUv = fraction.yx*vec2(-1,1)*100;
vUv = mix(0.5 + (uvo-0.5)*2,vUv+0.5,0.5);
vUv = 0.5 + (1.0 - abs( fract( vUv * 0.5 ) * 2 - 1.0 )-0.5)*0.98; // Eo.S. mirror code with cutted borders
vUv = (vUv-.5)*.9 + .5;

uv1 = (vUv-center)*uAspect.xy;

dist = MinDistB(vUv);
bdist = mix(dist,GetDistB(vUv),.2);
dist_c = clamp(GetDistB2 (center),.1,.4); //center distance

vec3 uv2 = multiply(vec3((vUv-.5)*MinDistB(vUv),MinDistB(vUv))/myzoom,RotMat)+CamPos;
glow = pow(sat(texture(sampler_noise_hq,.02*uv2).r-.6)*2,2);
//vUv += .003*glow*(texture(sampler_noise_mq,vUv*2+vec2(0,uTime/4).xy-.5));

float focus = sat(abs(GetDistB2(vUv)-dist_c)*1+.2);
float struc = GetBlurX(vUv,focus).r;

glow = sat(1-exp(-(GetBlur1(vUv).r))-.2);
q18 = 1;
ret = pow(struc,1) * (.2+(1-focus) *mix(dist,1-dist,q18)) * (1+.5*sin(uv2));
ret = mix(ret, vec3(0,1,glow*3), glow);

//distant light
//ret += pow(1-GetBlurX(vUv,.8).b,3)*(.5+.5*slow_roam_cos) *q19;

//Lamp
uv3 = uv1;
lamp = clamp01(1-4*length(uv3))*(struc)*clamp01(1-2*bdist)*1.8;
ret += (1-lum(ret))*lamp;
ret = 1-exp((-2)*ret);
//ret = GetPixel(vUv).r;

// laser

ret = ret + dots*(1+ret);

  fragColor = ret;
}
